('d42f61824be36d02c824d4d703cc683e','adminbappeda','adminbappeda','2017-07-24 08:05:22','202.169.233.108','202.169.233.108','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.1\",\"target\":\"Menerapkan secara nasional sistem dan upaya perlindungan sosial yang tepat bagi semua, termasuk kelompok yang paling miskin dan pada tahun 2030 mencapai cangkupan substansial bagi kelompok miskin dan rentan.\",\"id_target\":\"3\",\"id_parent_tujuan\":\"1\",\"perubahanKode\":\"false\"},\"_\":\"1500951493330\"}'),
