('d42f61824be36d02c824d4d703cc683e','adminbappeda','adminbappeda','2017-07-24 08:08:11','202.169.233.108','202.169.233.108','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.1\",\"target\":\"Pada tahun 2030 menjamin  bahwa semua laki-laki dan perempuan , khususnya masayarakat miskin dan rentan, memiliki hak sama terhadap sumber daya ekonomi, serta akses terhdap pelayanan dasar, kepemilikan dan kontrol atas tanah dan bentuk kepemilikan lain, warisan, sumber daya alam, teknologi baru dan jasa keuangan yang tepat, termasuk keuangan mikro.\",\"id_target\":\"4\",\"id_parent_tujuan\":\"1\",\"perubahanKode\":\"false\"},\"_\":\"1500951493332\"}'),
('d42f61824be36d02c824d4d703cc683e','adminbappeda','adminbappeda','2017-07-24 08:09:20','202.169.233.108','202.169.233.108','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.1\",\"target\":\"Pada tahun 2030, membangun ketahanan masyarakat miskin dan menghadapi situasi rentan, dan mengurangi kerentanan mereka terhadap kejadian ekstrim terkait iklim dan guncangan ekonomi, social, lingkungan dan bencana.\",\"id_target\":\"5\",\"id_parent_tujuan\":\"1\",\"perubahanKode\":\"false\"},\"_\":\"1500951493334\"}'),
('d42f61824be36d02c824d4d703cc683e','adminbappeda','adminbappeda','2017-07-24 08:11:24','202.169.233.108','202.169.233.108','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.1\",\"target\":\"Pada tahun 2030, membangun ketahanan masyarakat miskin dan mereka yang berada dalam kondisi rentan, dan mengurangi kerentanan mereka terhadap kejadian ekstrim terkait iklim dan guncangan ekonomi, sosial, lingkungan dan bencana.\",\"id_target\":\"5\",\"id_parent_tujuan\":\"1\",\"perubahanKode\":\"false\"},\"_\":\"1500951493336\"}'),
