('d42f61824be36d02c824d4d703cc683e','adminbappeda','adminbappeda','2017-07-24 08:49:17','202.169.233.108','202.169.233.108','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.2\",\"target\":\"Pada tahun 2030, menghilangkan segala bentuk kekurangan gizi, termasuk pada tahun 2015 mencapai target yang di sepakati secara internasional untuk anak pendek dan kurus  di bawah usia 5 tahun, dan memenuhi kebutuhan gizi remaja perempuan, ibu hamil dan menyusui serta manula\",\"id_target\":\"9\",\"id_parent_tujuan\":\"2\",\"perubahanKode\":\"false\"},\"_\":\"1500951493457\"}'),
