('e250d87d144dc731f61d6968a861fb09','adminbappeda','adminbappeda','2017-07-24 08:49:28','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.6\",\"target\":\"Pada tahun 2030, mencapai akses terhadap sanitasi dan kebersihan yang memadai dan merata bagi semua, dan menghentikan praktek buang air besar di tempat terbuka, memberikan perhatian khusus pada kebutuhan kaum perempuan, serta kelompok masyarakat rentan\",\"id_target\":\"49\",\"id_parent_tujuan\":\"6\",\"perubahanKode\":\"false\"},\"_\":\"1500859386817\"}'),
('3100469cdd95d524e3c32e93ab38a307','adminbappeda','adminbappeda','2017-07-24 08:51:31','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.4\",\"target\":\"Pada tahun 2030, menjamin bahwa semua anak perempuan dan anak laki-laki menyelesaikan SD-SMP tanpa dipungut biaya, setara, dan berkualitas, yang mengarah pada capaian pembelajaran yang relevan dan efektif.\",\"id_target\":\"29\",\"id_parent_tujuan\":\"4\",\"perubahanKode\":\"false\"},\"_\":\"1500860749921\"}'),
('37395874992a3b059f3cfe6e26b02bf7','adminbappeda','adminbappeda','2017-07-24 08:54:57','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.3\",\"target\":\"Pada tahun 2030, mengurangi rasio angka kematian ibu hingga kurang dari 70 per 100.000 kelahiran hidup\",\"id_target\":\"16\",\"id_parent_tujuan\":\"3\",\"perubahanKode\":\"false\"},\"_\":\"1500859016656\"}'),
('3100469cdd95d524e3c32e93ab38a307','adminbappeda','adminbappeda','2017-07-24 08:55:03','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.4\",\"target\":\"Pada tahun 2030, menjamin bahwa semua anak perempuan dan anak laki-laki memiliki akses terhadap perkembangan anak dan pengasuhan anak usia dini, pengasuhan, pendidikan pra sekolah dasar yang berkualitas, sehingga mereka siap untuk menempuh pendidikan dasar.\",\"id_target\":\"30\",\"id_parent_tujuan\":\"4\",\"perubahanKode\":\"false\"},\"_\":\"1500860749925\"}'),
('3100469cdd95d524e3c32e93ab38a307','adminbappeda','adminbappeda','2017-07-24 08:56:42','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.4\",\"target\":\"Pada tahun 2030, menjamin akses yang sama bagi semua perempuan dan laki-laki, terhadap pendidikan teknis, kejujuran dan pendidikan tinggi, termasuk universitas, yang terjangkau dan berkualitas.\",\"id_target\":\"31\",\"id_parent_tujuan\":\"4\",\"perubahanKode\":\"false\"},\"_\":\"1500860749927\"}'),
('3100469cdd95d524e3c32e93ab38a307','adminbappeda','adminbappeda','2017-07-24 08:58:05','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.4\",\"target\":\"Pada tahun 2030, Peningkatan secara signifikan jumlah pemuda dan orang dewasa yang memiliki ketrampilan yang relevan, termasuk ketrampilan teknik, dan kejuruan, untuk pekerjaan, pekerjaan yang layak dan kewirausahaan.\",\"id_target\":\"32\",\"id_parent_tujuan\":\"4\",\"perubahanKode\":\"false\"},\"_\":\"1500860749929\"}'),
('37395874992a3b059f3cfe6e26b02bf7','adminbappeda','adminbappeda','2017-07-24 08:59:01','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.3\",\"target\":\"Pada tahun 2030, mengakhiri kematian bayi baru lahir dan balita yang dapat dicegah, dengan seluruh negara berusaha menurunkan Angka Kematian Neonatal setidaknya hingga 12 per 1000 KH (Kelahiran Hidup)\",\"id_target\":\"17\",\"id_parent_tujuan\":\"3\",\"perubahanKode\":\"false\"},\"_\":\"1500859016658\"}'),
('3100469cdd95d524e3c32e93ab38a307','adminbappeda','adminbappeda','2017-07-24 08:59:24','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.4\",\"target\":\"pada tahun 2030, menghilangkan disparitas gender dalam pendidikan,dan menjamin akses yang sama untuk semua tingkat pendidikan dan pelatihan kejuruan, bagi masyarakat rentan termasuk penyandang cacat, masyarakat penduduk asli, dan anak-anak dalam kondisi rentan.\",\"id_target\":\"33\",\"id_parent_tujuan\":\"4\",\"perubahanKode\":\"false\"},\"_\":\"1500860749931\"}'),
('37395874992a3b059f3cfe6e26b02bf7','adminbappeda','adminbappeda','2017-07-24 08:59:37','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.3\",\"target\":\"Pada tahun 2030, mengakhiri kematian bayi baru lahir dan balita yang dapat dicegah, dengan seluruh negara berusaha menurunkan Angka Kematian Neonatal setidaknya hingga 12 per 1000 KH (Kelahiran Hidup) dan Angka Kematian Balita 25 per 1000\",\"id_target\":\"17\",\"id_parent_tujuan\":\"3\",\"perubahanKode\":\"false\"},\"_\":\"1500859016660\"}'),
('37395874992a3b059f3cfe6e26b02bf7','adminbappeda','adminbappeda','2017-07-24 09:00:33','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.3\",\"target\":\"Pada tahun 2030, mengakhiri epidemi AIDS, tuberculosis, malaria, dan penyakit tropis yang terabaikan dan memerangi hepatitis, penyakit bersumber air, dan penyakit menular lainya\",\"id_target\":\"18\",\"id_parent_tujuan\":\"3\",\"perubahanKode\":\"false\"},\"_\":\"1500859016662\"}'),
('3100469cdd95d524e3c32e93ab38a307','adminbappeda','adminbappeda','2017-07-24 09:00:43','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.4\",\"target\":\"Pada tahun 2030, menjamin bahwa semua remaja dan  proporsi dewasa tertentu, baik laki-laki maupun perempuan, memiliki kemampuan literasi dan numerasi.\",\"id_target\":\"34\",\"id_parent_tujuan\":\"4\",\"perubahanKode\":\"false\"},\"_\":\"1500860749933\"}'),
