('115dba5ec145019496b81fc1ba26f783','adminbappeda','adminbappeda','2017-07-24 09:32:23','202.169.233.105','202.169.233.105','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.2\",\"target\":\"Pada tahun 2020, mempertahankan keberagaman genetik benih, tanaman budidaya dan hewan ternak dan peliharaan dan spesies liar yang terkait, termasuk melalui bank benih dan tanaman yang dikelola dan dianekaragaman dengan baik di tingkat nasional, regional dan internasional, serta meningkatkan akses terhadap pembagian keuntungan yang adil dan merata, hasil dari pemanfaatan sumber daya genetik dan pengetahuan tradisonal, terkait, sebagaimana yang disepakati secara internasional.\\nJumlah varietas unggul tanaman dan hewan untuk pangan yang dilepas\",\"id_target\":\"12\",\"id_parent_tujuan\":\"2\",\"perubahanKode\":\"false\"},\"_\":\"1500861884689\"}'),
('3100469cdd95d524e3c32e93ab38a307','adminbappeda','adminbappeda','2017-07-24 09:34:18','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.4\",\"target\":\"Pada tahun 2020, Secara signifikan memperluas secara global, jumlah beasiswa bagi negara berkembang, khususnya negara kurang berkembang, negara berkembang pulau kecil, dan negara-negara Afrika, untuk mendaftar di pendidikan tinggi, termasuk pelatiha kejuruan, teknologi informasi dan komunikasi, program teknik, program rekayasa ilmiah, di negara maju dan negara berkemban lainnya.\",\"id_target\":\"37\",\"id_parent_tujuan\":\"4\",\"perubahanKode\":\"false\"},\"_\":\"1500860750062\"}'),
