('115dba5ec145019496b81fc1ba26f783','adminbappeda','adminbappeda','2017-07-24 09:40:54','202.169.233.105','202.169.233.105','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.2\",\"target\":\"Pada tahun 2020, mengelola keragaman genetik benih, tanaman budidaya dan hewan ternak dan peliharaan dan spesies liar yang terkait, termasuk melalui bank benih dan tanaman yang dikelola dan dianekaragaman dengan baik di tingkat nasional, regional dan internasional, serta meningkatkan akses terhadap pembagian keuntungan yang adil dan merata, hasil dari pemanfaatan sumber daya genetik dan pengetahuan tradisonal, terkait, sebagaimana yang disepakati secara internasional.\\nJumlah varietas unggul tanaman dan hewan untuk pangan yang dilepas\",\"id_target\":\"12\",\"id_parent_tujuan\":\"2\",\"perubahanKode\":\"false\"},\"_\":\"1500861884774\"}'),
('3100469cdd95d524e3c32e93ab38a307','adminbappeda','adminbappeda','2017-07-24 09:41:49','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.5\",\"target\":\"Mengakhiri segala bentuk diskriminasi terhadap kaum perempuan di mana pun.\",\"id_target\":\"39\",\"id_parent_tujuan\":\"5\",\"perubahanKode\":\"false\"},\"_\":\"1500860750067\"}'),
('3100469cdd95d524e3c32e93ab38a307','adminbappeda','adminbappeda','2017-07-24 09:45:17','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.6\",\"target\":\"Pada tahun 2030, meningkatkan kualitas air dengan mengurangi populasi, menghilangkan pembuangan dan meminimalkan pelepasan material dan bahan kimia berbahaya, mengurangi setengah proporsi air limbah yang tidak diolah, dan secara signifikan meningkatkan daur ulang serta penggunaan kembali barang daur ulang yang aman secara global.\",\"id_target\":\"50\",\"id_parent_tujuan\":\"6\",\"perubahanKode\":\"false\"},\"_\":\"1500860750070\"}'),
('3100469cdd95d524e3c32e93ab38a307','adminbappeda','adminbappeda','2017-07-24 09:46:53','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.6\",\"target\":\"Pada tahun 2030, secara signifikan meningkatkan efesinsi penggunaan air di semua sektor, dan menjamin  penggunaan dan pasokan air tawar yang berkelanjutan untuk mengatasi kelangkaan air, dan secara signifikan mengurangi jumlah orang yang menderita akibat kelangkaan air.\",\"id_target\":\"51\",\"id_parent_tujuan\":\"6\",\"perubahanKode\":\"false\"},\"_\":\"1500860750072\"}'),
('115dba5ec145019496b81fc1ba26f783','adminbappeda','adminbappeda','2017-07-24 09:49:42','202.169.233.105','202.169.233.105','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.3\",\"target\":\"Meningkatkan secara signifikan pembiayaan kesehatan dan rekruitmen, pengembangan, pelatihan, dan retensi tenaga kesehatan negara berkembang, khusunya negara kurang berkembang, dan negara berkembang pulau kecil\",\"id_target\":\"27\",\"id_parent_tujuan\":\"3\",\"perubahanKode\":\"false\"},\"_\":\"1500861884777\"}'),
('3100469cdd95d524e3c32e93ab38a307','adminbappeda','adminbappeda','2017-07-24 09:49:56','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.6\",\"target\":\"Pada tahun 2020, melindungi dan merestorasi ekosistem terkait sumber daya air, termasuk pegunungan, hutan, lahan basah, sungai, air tanah, dan danau.\",\"id_target\":\"53\",\"id_parent_tujuan\":\"6\",\"perubahanKode\":\"false\"},\"_\":\"1500860750074\"}'),
