('65740d5723229686588c7a928f7adf9b','adminbappeda','adminbappeda','2017-07-24 10:06:26','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"1\",\"kode_tujuan\":\"1.6\",\"target\":\"Pada tahun 2030, memperluas kerja sama dan dukungan internasional dalam hal pembangunan kapasitas bagi negara-negara berkembang, dalam program dan kegiatan terkait air dan sanitasi, termasuk pemanenan air, desalinasi, efesien air, pengolahan air limbah, daur ulang dan teknologi daur ulang.\",\"id_target\":\"54\",\"id_parent_tujuan\":\"6\",\"perubahanKode\":\"false\"},\"_\":\"1500865113434\"}'),
