('65740d5723229686588c7a928f7adf9b','adminbappeda','adminbappeda','2017-07-24 10:09:21','202.169.233.104','202.169.233.104','add-target','target_delete','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"delete\",\"id_target\":\"107\",\"_\":\"1500865113450\"}'),
('65740d5723229686588c7a928f7adf9b','adminbappeda','adminbappeda','2017-07-24 10:10:35','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"2\",\"kode_tujuan\":\"2.8\",\"target\":\"Mempertahankan pertumbuhan ekonomi per kapita sesuai dengan kondisi nasional dan, khususnya, setidaknya 7 persen pertumbuhan produk domestik bruto per tahun di negara kurang berkembang\",\"id_target\":\"108\",\"id_parent_tujuan\":\"8\",\"perubahanKode\":\"false\"},\"_\":\"1500865113457\"}'),
('65740d5723229686588c7a928f7adf9b','adminbappeda','adminbappeda','2017-07-24 10:12:15','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"2\",\"kode_tujuan\":\"2.8\",\"target\":\"Mencapai tingkat produktivitas ekonomi yang lebih tinggi, melalui diversifikasi, peningkatan dan inovasi teknologi, termasuk melalui fokus pada sektor yang memberi nilai tambah tinngi dan padat karya\",\"id_target\":\"109\",\"id_parent_tujuan\":\"8\",\"perubahanKode\":\"false\"},\"_\":\"1500865113459\"}'),
('65740d5723229686588c7a928f7adf9b','adminbappeda','adminbappeda','2017-07-24 10:13:46','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"2\",\"kode_tujuan\":\"2.8\",\"target\":\"Menggalakkan kebijakan pembangunan yang mendukung kegiatan produktif, penciptaan lapangan kerja layak, kewirausahaan, kreativitas dan inovasi, dan mendorong formalisasi dan pertumbuhan usaha mikro, kecil dan menengah, termasuk melalui akses pada jasa keuangan.\",\"id_target\":\"110\",\"id_parent_tujuan\":\"8\",\"perubahanKode\":\"false\"},\"_\":\"1500865113461\"}'),
('65740d5723229686588c7a928f7adf9b','adminbappeda','adminbappeda','2017-07-24 10:16:11','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"2\",\"kode_tujuan\":\"2.8\",\"target\":\"Pada tahun 2030, mencapai pekerjaan tetap dan produktif yang layak bagi semua perempuan dan laki-laki, termasuk bagi pemuda dan penyandang difabilitas, dan upah yang sama untuk pekerjaan yang sama nilainya.\",\"id_target\":\"112\",\"id_parent_tujuan\":\"8\",\"perubahanKode\":\"false\"},\"_\":\"1500865113463\"}'),
('65740d5723229686588c7a928f7adf9b','adminbappeda','adminbappeda','2017-07-24 10:18:04','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"2\",\"kode_tujuan\":\"2.8\",\"target\":\"Memperkuat kapasitas lembaga keuangan domestik untuk mendorong dan memperluas akses terhadap perbankan, asuransi dan jasa keuangan bagi semua.\",\"id_target\":\"117\",\"id_parent_tujuan\":\"8\",\"perubahanKode\":\"false\"},\"_\":\"1500865113465\"}'),
('65740d5723229686588c7a928f7adf9b','adminbappeda','adminbappeda','2017-07-24 10:20:04','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"2\",\"kode_tujuan\":\"2.8\",\"target\":\"Melindungi hak-hak tenaga kerja dan mempromosikan lingkungan kerja yang aman dan terjamin bagi semua pekerja, termasuk pekerja migran, khususnya pekerja migran perempuan, dan mereka yang bekerja dalam pekerjaan berbahaya.\",\"id_target\":\"115\",\"id_parent_tujuan\":\"8\",\"perubahanKode\":\"false\"},\"_\":\"1500865113467\"}'),
('65740d5723229686588c7a928f7adf9b','adminbappeda','adminbappeda','2017-07-24 10:23:27','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"2\",\"kode_tujuan\":\"2.8\",\"target\":\"Pada tahun 2020, mengembangkan dan mengoperasionalkan strategi global untuk ketenagakerjaan pemuda dan menerapkan the Global Jobs Pact of the International Labour Organization.\",\"id_target\":\"114\",\"id_parent_tujuan\":\"8\",\"perubahanKode\":\"false\"},\"_\":\"1500865113469\"}'),
