('ba823f295f4985ed224ca39c69b4673f','adminbappeda','adminbappeda','2017-07-24 13:03:32','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"4\",\"kode_tujuan\":\"4.17\",\"target\":\"Memobilisasi tambahan sumber daya keuangan untuk negara berkembang dari berbagai macam sumber.\",\"id_target\":\"201\",\"id_parent_tujuan\":\"17\",\"perubahanKode\":\"false\"},\"_\":\"1500874743285\"}'),
('ba823f295f4985ed224ca39c69b4673f','adminbappeda','adminbappeda','2017-07-24 13:05:58','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"4\",\"kode_tujuan\":\"4.17\",\"target\":\"Membantu negara-negara berkembang untuk mendapatkan keberlanjutan utang jangka panjang melalui kebijakan-kebijakan yang terkoordinasi yang ditunjukan untuk membantu pembiayaan utang, keringanan utuang dan restrukturisasi utang, yang sesuai, dan menyelesaikan utang luar negeri dari negara miskin yang berhutang besar untuk mengurangi tekanan utang.\",\"id_target\":\"202\",\"id_parent_tujuan\":\"17\",\"perubahanKode\":\"false\"},\"_\":\"1500874743287\"}'),
('ba823f295f4985ed224ca39c69b4673f','adminbappeda','adminbappeda','2017-07-24 13:06:11','202.169.233.104','202.169.233.104','add-target','target_delete','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"delete\",\"id_target\":\"203\",\"_\":\"1500874743289\"}'),
('ba823f295f4985ed224ca39c69b4673f','adminbappeda','adminbappeda','2017-07-24 13:10:48','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"4\",\"kode_tujuan\":\"4.17\",\"target\":\"Meningkatkan Kerjasama Utara-Selatan, Selatan-selatan dan kerjasama triangular secara regional dan internasional terkait, dan akses terhadap sains, teknologi dan inovasi dan meningkatkan berbagai pengetahuan berdasar kesepakatan timbal balik, termasuk melalui koordinasi yang lebih baik antara mekanisme yang telah ada, khususnya di tingkat Perserikatan Bangsa-bangsa (PBB), dan melalui mekanisme fasilitas teknologi global.\",\"id_target\":\"204\",\"id_parent_tujuan\":\"17\",\"perubahanKode\":\"false\"},\"_\":\"1500874743295\"}'),
('ba823f295f4985ed224ca39c69b4673f','adminbappeda','adminbappeda','2017-07-24 13:10:48','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"4\",\"kode_tujuan\":\"4.17\",\"target\":\"Meningkatkan Kerjasama Utara-Selatan, Selatan-selatan dan kerjasama triangular secara regional dan internasional terkait, dan akses terhadap sains, teknologi dan inovasi dan meningkatkan berbagai pengetahuan berdasar kesepakatan timbal balik, termasuk melalui koordinasi yang lebih baik antara mekanisme yang telah ada, khususnya di tingkat Perserikatan Bangsa-bangsa (PBB), dan melalui mekanisme fasilitas teknologi global.\",\"id_target\":\"204\",\"id_parent_tujuan\":\"17\",\"perubahanKode\":\"false\"},\"_\":\"1500874743296\"}'),
