('ba823f295f4985ed224ca39c69b4673f','adminbappeda','adminbappeda','2017-07-24 13:15:31','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"4\",\"kode_tujuan\":\"4.17\",\"target\":\"Mengoperasionalisasikan secara penuh bank teknologi dan sains, mekanisme pembangunan kapasitas teknologi dan inovasi untuk negara kurang berkembang pada tahun 2017 dan meningkatkan penggunaan teknologi yang memampukan, khususnya teknologi informasi dan komunikasi.\",\"id_target\":\"206\",\"id_parent_tujuan\":\"17\",\"perubahanKode\":\"false\"},\"_\":\"1500874743306\"}'),
('ba823f295f4985ed224ca39c69b4673f','adminbappeda','adminbappeda','2017-07-24 13:18:41','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"4\",\"kode_tujuan\":\"4.17\",\"target\":\"Meningkatkan dukungan internasional untuk melaksankan pembangunan kapasitas yang efektif dan sesuai target  di negara berkembang untuk mendukung rencana nasional untuk melaksanakan seluruh tujuan pembangunan berkelanjutan, termasuk melalui kerjasama Utara-Selatan, Selatan-Selatan dan triangular.\",\"id_target\":\"207\",\"id_parent_tujuan\":\"17\",\"perubahanKode\":\"false\"},\"_\":\"1500874743308\"}'),
