('ba823f295f4985ed224ca39c69b4673f','adminbappeda','adminbappeda','2017-07-24 13:27:37','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"4\",\"kode_tujuan\":\"4.17\",\"target\":\"Pada 2020, meningkatkan dukungan pengembangan kapasitas untuk negara berkembang, termasuk negara kurang berkembang dan negara berkembang pulau kecil, untuk meningkatkan secara signifikan ketersediaan data berkualitas tinggi, tepat waktu dan dapat dipercaya, yang terpilah berdasarkan pendapatan, gender, umur, ras, etnis, status migrasi, difabilitas, lokasi geogrfi dan karekteristik lainya yang relevan dengan konteks nasional.\",\"id_target\":\"215\",\"id_parent_tujuan\":\"17\",\"perubahanKode\":\"false\"},\"_\":\"1500874743339\"}'),
