('923d35053935c9a665e6be2975fe55b6','adminbappeda','adminbappeda','2017-07-24 15:06:11','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"2\",\"kode_tujuan\":\"2.9\",\"target\":\"Mengembangkan infrastruktur yang berkualitas, andal, berkelanjutan dan tangguh, termasuk infrastruktur regional dan lintas batas, untuk mendukung pembangunan ekonomi dan kesejahteraan manusia, dengan fokus pada akses yang terjangkau dan merata bagi semua\",\"id_target\":\"120\",\"id_parent_tujuan\":\"9\",\"perubahanKode\":\"false\"},\"_\":\"1500880649867\"}'),
