('923d35053935c9a665e6be2975fe55b6','adminbappeda','adminbappeda','2017-07-24 15:08:26','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"2\",\"kode_tujuan\":\"2.9\",\"target\":\"Mempromosikan industrilisasi inklusif dan bekelanjutan, dan pada tahun 2030, secara signifikan meningkatkan proporsi industri dalam lapangan kerja dan produk domestik bruto, sejalan dengan kondisi nasional, dan meningkatkan dua kali lipat proporsinya di negara kurang berkembang\",\"id_target\":\"121\",\"id_parent_tujuan\":\"9\",\"perubahanKode\":\"false\"},\"_\":\"1500880649869\"}'),
('923d35053935c9a665e6be2975fe55b6','adminbappeda','adminbappeda','2017-07-24 15:09:12','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"2\",\"kode_tujuan\":\"2.9\",\"target\":\"Meningkatkan akses industri dan perusahaan skala kecil, khususnya di negara berkembang, terhadap jasa keuangan, termasuk kredit terjangkau, dan mengintegrasikan ke dalam rantai nilai dan pasar\",\"id_target\":\"122\",\"id_parent_tujuan\":\"9\",\"perubahanKode\":\"false\"},\"_\":\"1500880649871\"}'),
('923d35053935c9a665e6be2975fe55b6','adminbappeda','adminbappeda','2017-07-24 15:11:39','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"2\",\"kode_tujuan\":\"2.9\",\"target\":\"Pada tahun 2030, meningkatkan infrastuktur dan retrofit industri agar dapat berkelanjutan, dengan peningkatan efisiensi penggunaan sumberdaya dan adopsi yang lebih baik dari teknologi dan proses industri yang bersih dan ramah lingkungan, yang dilaksanakan semua negara sesuai kemampuan masing-masing\",\"id_target\":\"123\",\"id_parent_tujuan\":\"9\",\"perubahanKode\":\"false\"},\"_\":\"1500880649873\"}'),
('923d35053935c9a665e6be2975fe55b6','adminbappeda','adminbappeda','2017-07-24 15:12:24','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"2\",\"kode_tujuan\":\"2.9\",\"target\":\"Pada tahun 2030, meningkatkan infrastuktur dan retrofit industri agar dapat berkelanjutan, dengan peningkatan efisiensi penggunaan sumberdaya dan adopsi yang lebih baik dari teknologi dan proses industri bersih dan ramah lingkungan, yang dilaksanakan semua negara sesuai kemampuan masing-masing\",\"id_target\":\"123\",\"id_parent_tujuan\":\"9\",\"perubahanKode\":\"false\"},\"_\":\"1500880649875\"}'),
('923d35053935c9a665e6be2975fe55b6','adminbappeda','adminbappeda','2017-07-24 15:14:13','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"2\",\"kode_tujuan\":\"2.9\",\"target\":\"Memperkuat riset ilmiah, meningkatkan kapabilitas teknologi sektor industri di semua negara, terutama negara-negara berkembang, teermasuk pada tahun 2030, mendorong inovasi secara subtansial meningkatkan jumlah pekerja penelitian dan mengembangkan per 1 juta orang dan meningkatkan pembelanjaan publik dan swasta untuk penelitian dan pengembangan\",\"id_target\":\"124\",\"id_parent_tujuan\":\"9\",\"perubahanKode\":\"false\"},\"_\":\"1500880649877\"}'),
('923d35053935c9a665e6be2975fe55b6','adminbappeda','adminbappeda','2017-07-24 15:16:13','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"2\",\"kode_tujuan\":\"2.9\",\"target\":\"Secara signifikan meningkatkan akses terhadap teknologi informasi dan komunikasi dan mengusahakan penyediaan akses universal dan terjangkau internet di negara-negara kurang berkembang pada tahun 2020\",\"id_target\":\"125\",\"id_parent_tujuan\":\"9\",\"perubahanKode\":\"false\"},\"_\":\"1500880649879\"}'),
('923d35053935c9a665e6be2975fe55b6','adminbappeda','adminbappeda','2017-07-24 15:16:25','202.169.233.104','202.169.233.104','add-target','target_delete','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"delete\",\"id_target\":\"126\",\"_\":\"1500880649881\"}'),
('923d35053935c9a665e6be2975fe55b6','adminbappeda','adminbappeda','2017-07-24 15:18:47','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"2\",\"kode_tujuan\":\"2.10\",\"target\":\"Pada tahun 2030, secara progresif mencapai dan mempertahankan pertumbuhan pendapatan penduduk yang berada di bawah 40% dari populasi pada tingkat yang lebih tinggi dari rata-rata nasional\",\"id_target\":\"137\",\"id_parent_tujuan\":\"10\",\"perubahanKode\":\"false\"},\"_\":\"1500880649888\"}'),
('923d35053935c9a665e6be2975fe55b6','adminbappeda','adminbappeda','2017-07-24 15:21:26','202.169.233.104','202.169.233.104','add-target','target_update','','{\"Module\":\"AddTarget\",\"option\":\"target\",\"action\":\"update\",\"data\":{\"id_pilar\":\"2\",\"kode_tujuan\":\"2.10\",\"target\":\"Menjamin kesempatan yang sama dan mengurangi kesenjangan hasil, termasuk dengan menghapus hukum, kebijakan dan praktik yang diskriminatif dan mempromosikan legislasi, kebijakan dan tindakan yang tepat terkait legislasi dan kebijakan tersebut\",\"id_target\":\"137\",\"id_parent_tujuan\":\"10\",\"perubahanKode\":\"false\"},\"_\":\"1500880649890\"}'),
