('2f1246a9bd5d485e886f89903fbfcbdd','adminbappeda','adminbappeda','2017-10-04 09:17:32','202.169.233.101','202.169.233.101','add-tujuan','tujuan_update','','{\"Module\":\"AddTujuan\",\"action\":\"update\",\"option\":\"tujuan\",\"data\":{\"id_pilar\":\"3\",\"id_tujuan\":\"14\",\"tujuan\":\"Melestarikan dan memanfaatkan secara berkelanjutan sumber daya kelautan dan samudera untuk pembangunan berkelanjutan.\"},\"_\":\"1507176470787\"}'),
('2f1246a9bd5d485e886f89903fbfcbdd','adminbappeda','adminbappeda','2017-10-04 09:18:03','202.169.233.101','202.169.233.101','add-tujuan','tujuan_update','','{\"Module\":\"AddTujuan\",\"action\":\"update\",\"option\":\"tujuan\",\"data\":{\"id_pilar\":\"3\",\"id_tujuan\":\"15\",\"tujuan\":\"Melindungi, merestorasi, dan meningkatkan pemanfaatan berkelanjutan ekosistem daratan, mengelola hutan secara lestari, menghentikan penggurunan, memulihkan degradasi lahan, serta menghenti-kan kehilangan keanekaragaman hayati\"},\"_\":\"1507176470789\"}'),
