(2,'select a.id, a.user_id, b.group_id, b.description group_name \r\nfrom users a, groups b, group_has_users c \r\nwhere a.user_id=c.user_id and b.group_id=c.group_id and a.active=1','select data user',NULL),
(3,'insert into user_has_messages (user_id, msg_id)\r\nselect user_id, 2 from group_has_users a where group_id=\'op_pendataan\'','insert message to user',NULL),
