(10,'INSERT INTO `modules` (`module_id`, `module`, `name`, `description`, `menu`, `iconcls`, `icon`, `active`, `onmenu`, `onview`)\nVALUES\n	(\'masterdata-kegiatan\', \'MDKegiatan\', \'Kegiatan Pemerintahan\', \'Pengelolaan Data Kegiatan Pemerintah\', \'Master Data/\', \'icon-module\', \'icon.png\', 1, 1, \'tabpanel\');# 1 row affected.\n\n\nINSERT INTO `actions` (`module_id`, `action_id`, `option`, `action`, `description`, `log`)\nVALUES\n	(\'masterdata-kegiatan\', \'kegiatan_list\', \'kegiatan\', \'list\', \'Menampilkan Daftar Data Kegiatan Pemerintah\', 1),\n	(\'masterdata-kegiatan\', \'kegiatan_export\', \'kegiatan\', \'export\', \'Export ke Excel Daftar Data Kegiatan Pemerintah\', 1),\n	(\'masterdata-kegiatan\', \'kegiatan_add\', \'kegiatan\', \'add\', \'Tambah Daftar Data Kegiatan Pemerintah\', 1),\n	(\'masterdata-kegiatan\', \'kegiatan_edit\', \'kegiatan\', \'edit\', \'Edit Daftar Data Kegiatan Pemerintah\', 1),\n	(\'masterdata-kegiatan\', \'kegiatan_del\', \'kegiatan\', \'del\', \'Hapus Daftar Data Kegiatan Pemerintah\', 1),\n	(\'masterdata-kegiatan\', \'kegiatan_print\', \'kegiatan\', \'print\', \'Cetak Daftar Data Kegiatan Pemerintah\', 1),\n	(\'masterdata-kegiatan\', \'kegiatan_printPDF\', \'kegiatan\', \'printPDF\', \'Cetak ke PDF Daftar Kegiatan Pemerintah\', 1)\n	;# 7 rows affected.','Master Data Kegiatan',NULL),
(11,'INSERT INTO `modules` (`module_id`, `module`, `name`, `description`, `menu`, `iconcls`, `icon`, `active`, `onmenu`, `onview`) \nVALUES \n(\'kegiatan-usulan-daftar\', \'KegiatanUsulanDaftar\', \'Daftar Usulan Kegiatan\', \'Daftar Usulan Kegiatan\', \'Perencanaan/\', \'icon-module\', \'icon.png\', 1, 1, \'tabpanel\'); \n\nINSERT INTO `actions` (`module_id`, `action_id`, `option`, `action`, `description`, `log`) VALUES \n( \'kegiatan-usulan-daftar\',\'kegiatan_export\',\'kegiatan\',\'export\',\'Export ke Excel Daftar Data Usulan Kegiatan\',0 ), \n( \'kegiatan-usulan-daftar\',\'kegiatan_list\',\'kegiatan\',\'list\',\'Menampilkan Daftar Data Usulan Kegiatan\',0 );','Daftar Usulan Kegiatan',NULL),
(12,'INSERT INTO `modules` (`module_id`, `module`, `name`, `description`, `menu`, `iconcls`, `icon`, `active`, `onmenu`, `onview`) \nVALUES \n(\'kegiatan-rkpd-daftar\', \'KegiatanRKPDDaftar\', \'Daftar RKPD\', \'Daftar Rencana Kegiatan Perangkat Daerah\', \'Perencanaan/\', \'icon-module\', \'icon.png\', 1, 1, \'tabpanel\'); \n\nINSERT INTO `actions` (`module_id`, `action_id`, `option`, `action`, `description`, `log`) VALUES \n( \'kegiatan-rkpd-daftar\',\'kegiatan_export\',\'kegiatan\',\'export\',\'Export ke Excel Daftar Data RKPD\',0 ), \n( \'kegiatan-rkpd-daftar\',\'kegiatan_list\',\'kegiatan\',\'list\',\'Menampilkan Daftar Data RKPD\',0 ),\n( \'kegiatan-rkpd-daftar\',\'kegiatan_import\',\'kegiatan\',\'import\',\'Import Dari Data Usulan Kegiatan\',0 ) ;','Daftar Kegiatan RKPD',NULL),
(13,'DROP FUNCTION IF EXISTS get_instansi;\nDELIMITER $$\nCREATE FUNCTION get_instansi(ptahun int, pid_instansi int)\n  RETURNS varchar(255)\nBEGIN\n	DECLARE hasil varchar(255);\n  	select instansi into hasil from tr_instansi where tahun=ptahun and id_instansi=pid_instansi;\n  	return hasil;\nEND;\n$$\nDELIMITER ;\n\nDROP FUNCTION IF EXISTS get_urusan;\nDELIMITER $$\nCREATE FUNCTION get_urusan(ptahun int, pid_urusan int)\n  RETURNS varchar(255)\nBEGIN\n	DECLARE hasil varchar(255);\n  	select urusan into hasil from tr_urusan where tahun=ptahun and id_urusan=pid_urusan;\n  	return hasil;\nEND;\n$$\nDELIMITER ;\n\n\nDROP FUNCTION IF EXISTS get_kegiatan;\nDELIMITER $$\nCREATE FUNCTION get_kegiatan(ptahun int, pid_kegiatan int)\n  RETURNS varchar(255)\nBEGIN\n	DECLARE hasil varchar(255);\n  	select kegiatan into hasil from tr_kegiatan where tahun=ptahun and id_kegiatan=pid_kegiatan;\n  	return hasil;\nEND;\n$$\nDELIMITER ;\n\nSELECT id_usulan, kode_usulan, \nid_instansi, \nget_instansi(tahun, id_instansi) instansi,\nid_urusan, \nget_urusan(tahun, id_urusan) urusan,\nid_program, \nget_program(tahun, id_program) program,\nid_kegiatan, \nget_kegiatan(tahun, id_kegiatan) kegiatan,\n                tahun, sasaran, volume, lokasi, \n                apbd_kab, apbd_prop, apbn_hpln, blud, alokasi_n1, sumber_lain, total, \n                keterangan, disetujui, user_input, \n                tgl_input, user_update, tgl_update, capaian_program, flagpik,\n                \'\' ket_output, \'\' ket_outcome\n            FROM kegiatan_usulan  where tahun=2014            \n\nCREATE DEFINER=`root`@`localhost` PROCEDURE `UsulanToRKPD`(ptahun int, pid_usulan int, puser_id varchar(200))\nBEGIN\n/* 	Lakukan hapus data terlebih dahulu,\n	Data RKPD otomatis diperbaharui berdasar data Usulan\n*/\n	delete from kegiatan_rkpd_output \n    where id_rkpd=(select id_rkpd from kegiatan_rkpd where tahun=ptahun and id_usulan=pid_usulan);\n	\n    delete from kegiatan_rkpd_outcome \n    where id_rkpd=(select id_rkpd from kegiatan_rkpd where tahun=ptahun and id_usulan=pid_usulan);\n    \n	delete from kegiatan_rkpd where tahun=ptahun and id_usulan=pid_usulan;\n    \n/*\n	Selesai hapus data`\n*/\n	insert into kegiatan_rkpd( `id_rkpd`, `kode_rkpd`, `id_usulan`, `id_instansi`, `id_urusan`, `id_program`, `id_kegiatan`,\n		`tahun`, `sasaran`, `volume`, `lokasi`, `apbd_kab`, `apbd_prop`, \n		`apbn_hpln`, `blud`, `alokasi_n1`, `sumber_lain`, `total`, `keterangan`, `disetujui`,\n		`user_input`, `tgl_input`, `user_update`, `tgl_update`, `capaian_program`, `keterangan_rkpd`, `flagpik`\n	) \n	select `id_usulan`,`kode_usulan`, `id_usulan`, `id_instansi`, `id_urusan`, `id_program`, `id_kegiatan`,\n		`tahun`, `sasaran`, `volume`, `lokasi`, `apbd_kab`, `apbd_prop`,\n		`apbn_hpln`, `blud`, `alokasi_n1`, `sumber_lain`, `total`, \'\', 0,\n		puser_id, now(), puser_id, now(), `capaian_program`, `keterangan`, `flagpik`\n	from kegiatan_usulan\n	where tahun=ptahun and id_usulan=pid_usulan;\n\n	INSERT INTO `kegiatan_rkpd_output` ( `tahun`, `id_rkpd`, `id_usulan_output`, `indikator`, `nilai`, `jml_anggaran`,\n		`user_input`, `tgl_input`, `user_update`, `tgl_update`,\n		`nilai_thn_1`, `ket`, `flag_pik`, `flag_arg`, `flag_nangkis`, `no_urut`)\n	select  `tahun`, `id_usulan`, `id_usulan_output`, `indikator`, `nilai`, `jml_anggaran`, \n		puser_id, now(), puser_id, now(), \n		`nilai_thn_1`, `ket`, `flag_pik`, `flag_arg`, `flag_nangkis`, `no_urut` \n	from kegiatan_usulan_output\n	where tahun=ptahun and id_usulan=pid_usulan;\n\n	INSERT INTO `kegiatan_rkpd_outcome` ( `tahun`, `id_rkpd`, `id_usulan_outcome`, `indikator`, `nilai`,\n		`user_input`, `tgl_input`, `user_update`, `tgl_update`, `nilai_thn_1`, `ket`, `no_urut`)\n	select `tahun`, `id_usulan`, `id_usulan_outcome`, `indikator`, `nilai`, \n		puser_id, now(), puser_id, now(), `nilai_thn_1`, `ket`, `no_urut` \n	from kegiatan_usulan_outcome\n	where tahun=ptahun and id_usulan=pid_usulan;\n\n END','Buat Function/Procedure',NULL),
(14,'INSERT INTO `modules` (`module_id`, `module`, `name`, `description`, `menu`, `iconcls`, `icon`, `active`, `onmenu`, `onview`)\nVALUES (\'lap-rekap-angg-inst\', \'LapRekapAnggaranInstansi\', \'Rekap Anggaran Per Instansi\', \'Laporan Rekap Anggaran Per Instansi\', \'Laporan/\', \'icon-module\', \'icon.png\', 1, 1, \'tabpanel\');\n		\n\nINSERT INTO `actions` (`module_id`, `action_id`, `option`, `action`, `description`, `log`) VALUES \n ( \'lap-rekap-angg-inst\',\'kegiatan_export\',\'kegiatan\',\'export\',\'Export ke Excel Daftar Data Rekap Anggaran Per Instansi\',0 ),  \n ( \'lap-rekap-angg-inst\',\'kegiatan_import\',\'kegiatan\',\'import\',\'Import Dari Data Rekap Anggaran Per Instansi\',0 ),  \n ( \'lap-rekap-angg-inst\',\'kegiatan_list\',\'kegiatan\',\'list\',\'Menampilkan Daftar Data Rekap Anggaran Per Instansi\',0 ) ;','Laporan Rekap Anggaran',NULL),
(15,'INSERT INTO `modules` (`module_id`, `module`, `name`, `description`, `menu`, `iconcls`, `icon`, `active`, `onmenu`, `onview`)\n			VALUES (\'lap-rekap-tahunan-ins\', \'LapRekapTahunanInstansi\', \'Rekap Anggaran Tahunan Per Instansi\', \'Laporan Rekap Anggaran Tahunan Per Instansi\', \'Laporan/\', \'icon-module\', \'icon.png\', 1, 1, \'tabpanel\');\n		\n\nINSERT INTO `actions` (`module_id`, `action_id`, `option`, `action`, `description`, `log`) VALUES \n ( \'lap-rekap-tahunan-ins\',\'rekap_export\',\'rekap\',\'export\',\'Export ke Excel Daftar Data Rekap Anggaran Tahunan Per Instansi\',0 ),  \n ( \'lap-rekap-tahunan-ins\',\'rekap_import\',\'rekap\',\'import\',\'Import Dari Data Rekap Anggaran Tahunan Per Instansi\',0 ),  \n ( \'lap-rekap-tahunan-ins\',\'rekap_list\',\'rekap\',\'list\',\'Menampilkan Daftar Data Rekap Anggaran Tahunan Per Instansi\',0 ) ;','laporan Rekap Tahunan Per Instansi',NULL),
(16,'INSERT INTO `modules` (`module_id`, `module`, `name`, `description`, `menu`, `iconcls`, `icon`, `active`, `onmenu`, `onview`)\n			VALUES (\'lap-rekap-tahunan-urusan\', \'LapRekapTahunanUrusan\', \'Rekap Anggaran Tahunan Per Urusan\', \'Laporan Rekap Anggaran Tahunan Per Urusan\', \'Laporan/\', \'icon-module\', \'icon.png\', 1, 1, \'tabpanel\');\n		\n\nINSERT INTO `actions` (`module_id`, `action_id`, `option`, `action`, `description`, `log`) VALUES \n ( \'lap-rekap-tahunan-urusan\',\'rekap_export\',\'rekap\',\'export\',\'Export ke Excel Daftar Data Rekap Anggaran Tahunan Per Urusan\',0 ),  \n ( \'lap-rekap-tahunan-urusan\',\'rekap_import\',\'rekap\',\'import\',\'Import Dari Data Rekap Anggaran Tahunan Per Urusan\',0 ),  \n ( \'lap-rekap-tahunan-urusan\',\'rekap_list\',\'rekap\',\'list\',\'Menampilkan Daftar Data Rekap Anggaran Tahunan Per Urusan\',0 ) ;','laporan Rekap Tahunan Per Urusan',NULL),
(17,'INSERT INTO `modules` (`module_id`, `module`, `name`, `description`, `menu`, `iconcls`, `icon`, `active`, `onmenu`, `onview`)\n			VALUES (\'lap-rekap-tahunan-prog\', \'LapRekapTahunanProgram\', \'Rekap Anggaran Tahunan Per Program\', \'Laporan Rekap Anggaran Tahunan Per Program\', \'Laporan/\', \'icon-module\', \'icon.png\', 1, 1, \'tabpanel\');\n		\n\nINSERT INTO `actions` (`module_id`, `action_id`, `option`, `action`, `description`, `log`) VALUES \n ( \'lap-rekap-tahunan-prog\',\'rekap_export\',\'rekap\',\'export\',\'Export ke Excel Daftar Data Rekap Anggaran Tahunan Per Program\',0 ),  \n ( \'lap-rekap-tahunan-prog\',\'rekap_import\',\'rekap\',\'import\',\'Import Dari Data Rekap Anggaran Tahunan Per Program\',0 ),  \n ( \'lap-rekap-tahunan-prog\',\'rekap_list\',\'rekap\',\'list\',\'Menampilkan Daftar Data Rekap Anggaran Tahunan Per Program\',0 ) ;\n \n ','laporan Rekap Tahunan Per Program',NULL),
(18,'INSERT INTO `modules` (`module_id`, `module`, `name`, `description`, `menu`, `iconcls`, `icon`, `active`, `onmenu`, `onview`)\n			VALUES (\'lap-urusan-program-kegiatan\', \'LapRekapUrusanProgramKegiatan\', \'Rekap Urusan/Program/Kegiatan\', \'Laporan Rekap Anggaran Rekap Anggaran Urusan/Program/Kegiatan Instansi\', \'Laporan/\', \'icon-module\', \'icon.png\', 1, 1, \'tabpanel\');\n		\n\nINSERT INTO `actions` (`module_id`, `action_id`, `option`, `action`, `description`, `log`) VALUES \n ( \'lap-urusan-program-kegiatan\',\'rekap_export\',\'rekap\',\'export\',\'Export ke Excel Daftar Data Rekap Anggaran Urusan/Program/Kegiatan Instansi\',0 ),  \n ( \'lap-urusan-program-kegiatan\',\'rekap_import\',\'rekap\',\'import\',\'Import Dari Data Rekap Anggaran Urusan/Program/Kegiatan Instansi\',0 ),  \n ( \'lap-urusan-program-kegiatan\',\'rekap_list\',\'rekap\',\'list\',\'Menampilkan Daftar Data Rekap Anggaran Urusan/Program/Kegiatan Instansi\',0 ) ;\n \n ','Laporan Urusan/Program/Kegiatan Instansi',NULL),
(19,'select * from modules \n\nselect distinct concat(\'update modules set menu=\'\'\'\' where menu=\'\'\',menu,\'\'\'\') from modules\n\nupdate modules set menu=\'\' where menu=\'\'\n\nupdate modules set menu=\'010;Developer\' where menu=\'01;Developer/\';\nupdate modules set menu=\'070;Eksekutif/010;RKPD/\' where menu=\'Eksekutif/01;RKPD/\';\nupdate modules set menu=\'070;Eksekutif/020;PPAS/\' where menu=\'Eksekutif/02;PPAS/\';\nupdate modules set menu=\'060;Perencanaan/\' where menu=\'04;Perencanaan/\';\nupdate modules set menu=\'080;Laporan/\' where menu=\'Laporan/\';\nupdate modules set menu=\'020;Administrator/\' where menu=\'02;Administrator/\';\nupdate modules set menu=\'040;Master Data/\' where menu=\'03;Master Data/\';\nupdate modules set menu=\'050;RPJMD/\' where menu=\'04;RPJMD/\';\nupdate modules set menu=\'100;Utility/\' where menu=\'Utility/\';\nupdate modules set menu=\'030;Konfigurasi/\' where menu=\'Konfigurasi/\';\nupdate modules set menu=\'041;Referensi/\' where menu=\'Referensi/\';','Update urutan Menu ',NULL),
(20,'DELIMITER $$\r\n\r\nUSE `teppa`$$\r\n\r\nDROP TRIGGER /*!50032 IF EXISTS */ `update_anggaran`$$\r\n\r\nCREATE\r\n    /*!50017 DEFINER = \'teppa\'@\'192.168.%\' */\r\n    TRIGGER `update_anggaran` AFTER UPDATE ON `kegiatan_realisasi_target` \r\n    FOR EACH ROW BEGIN\r\n  IF NEW.`keu_b11` <> OLD.`keu_b11` \r\n  THEN \r\n  UPDATE \r\n    kegiatan_realisasi \r\n  SET\r\n    anggaran = NEW.`keu_b01` + NEW.`keu_b02` + NEW.`keu_b03` + NEW.`keu_b04` + NEW.`keu_b05` + NEW.`keu_b06` + NEW.`keu_b07` + NEW.`keu_b08` + NEW.`keu_b09` + NEW.`keu_b10` + NEW.`keu_b11` + NEW.`keu_b12` \r\n  WHERE tahun = OLD.tahun \r\n    AND bulan = 11 \r\n    AND kode_instansi = OLD.kode_instansi \r\n    AND kode_kegiatan = OLD.kode_kegiatan ;\r\n  END IF ;\r\n  IF NEW.`keu_b12` <> OLD.`keu_b12` \r\n  THEN \r\n  UPDATE \r\n    kegiatan_realisasi \r\n  SET\r\n    anggaran = NEW.`keu_b01` + NEW.`keu_b02` + NEW.`keu_b03` + NEW.`keu_b04` + NEW.`keu_b05` + NEW.`keu_b06` + NEW.`keu_b07` + NEW.`keu_b08` + NEW.`keu_b09` + NEW.`keu_b10` + NEW.`keu_b11` + NEW.`keu_b12` \r\n  WHERE tahun = OLD.tahun \r\n    AND bulan = 12 \r\n    AND kode_instansi = OLD.kode_instansi \r\n    AND kode_kegiatan = OLD.kode_kegiatan ;\r\n  END IF ;\r\nEND;\r\n$$\r\n\r\nDELIMITER ;','Triger',NULL),
(21,'ALTER TABLE kegiatan_realisasi \nADD COLUMN target_keuangan double AFTER koordinator,\nADD COLUMN target_fisik double AFTER realisasi_keuangan_prosen, \nADD COLUMN target_kinerja double AFTER realisasi_fisik_prosen;\n\nUPDATE kegiatan_realisasi a\nINNER JOIN ( SELECT * FROM kegiatan_realisasi_target) b\nON b.kode_kegiatan = a.kode_kegiatan AND b.tahun = a.tahun AND a.tahun=2015 AND a.bulan = 1	\nSET a.target_fisik = b.fisik_b01, a.target_keuangan = b.keu_b01, a.target_kinerja = b.kinerja_b01;\n\nUPDATE kegiatan_realisasi a\nINNER JOIN ( SELECT * FROM kegiatan_realisasi_target) b\nON b.kode_kegiatan = a.kode_kegiatan AND b.tahun = a.tahun AND a.tahun=2015 AND a.bulan = 2	\nSET a.target_fisik = b.fisik_b02, a.target_keuangan = b.keu_b02, a.target_kinerja = b.kinerja_b02;\n\nUPDATE kegiatan_realisasi a\nINNER JOIN ( SELECT * FROM kegiatan_realisasi_target) b\nON b.kode_kegiatan = a.kode_kegiatan AND b.tahun = a.tahun AND a.tahun=2015 AND a.bulan = 3	\nSET a.target_fisik = b.fisik_b03, a.target_keuangan = b.keu_b03, a.target_kinerja = b.kinerja_b03;\n\nUPDATE kegiatan_realisasi a\nINNER JOIN ( SELECT * FROM kegiatan_realisasi_target) b\nON b.kode_kegiatan = a.kode_kegiatan AND b.tahun = a.tahun AND a.tahun=2015 AND a.bulan = 4	\nSET a.target_fisik = b.fisik_b04, a.target_keuangan = b.keu_b04, a.target_kinerja = b.kinerja_b04;\n\nUPDATE kegiatan_realisasi a\nINNER JOIN ( SELECT * FROM kegiatan_realisasi_target) b\nON b.kode_kegiatan = a.kode_kegiatan AND b.tahun = a.tahun AND a.tahun=2015 AND a.bulan = 5	\nSET a.target_fisik = b.fisik_b05, a.target_keuangan = b.keu_b05, a.target_kinerja = b.kinerja_b05;\n\nUPDATE kegiatan_realisasi a\nINNER JOIN ( SELECT * FROM kegiatan_realisasi_target) b\nON b.kode_kegiatan = a.kode_kegiatan AND b.tahun = a.tahun AND a.tahun=2015 AND a.bulan = 6\nSET a.target_fisik = b.fisik_b06, a.target_keuangan = b.keu_b06, a.target_kinerja = b.kinerja_b06;\n\nUPDATE kegiatan_realisasi a\nINNER JOIN ( SELECT * FROM kegiatan_realisasi_target) b\nON b.kode_kegiatan = a.kode_kegiatan AND b.tahun = a.tahun AND a.tahun=2015 AND a.bulan = 7	\nSET a.target_fisik = b.fisik_b07, a.target_keuangan = b.keu_b07, a.target_kinerja = b.kinerja_b07;\n\nUPDATE kegiatan_realisasi a\nINNER JOIN ( SELECT * FROM kegiatan_realisasi_target) b\nON b.kode_kegiatan = a.kode_kegiatan AND b.tahun = a.tahun AND a.tahun=2015 AND a.bulan = 8	\nSET a.target_fisik = b.fisik_b08, a.target_keuangan = b.keu_b08, a.target_kinerja = b.kinerja_b08;\n\nUPDATE kegiatan_realisasi a\nINNER JOIN ( SELECT * FROM kegiatan_realisasi_target) b\nON b.kode_kegiatan = a.kode_kegiatan AND b.tahun = a.tahun AND a.tahun=2015 AND a.bulan = 9	\nSET a.target_fisik = b.fisik_b09, a.target_keuangan = b.keu_b09, a.target_kinerja = b.kinerja_b09;\n\nUPDATE kegiatan_realisasi a\nINNER JOIN ( SELECT * FROM kegiatan_realisasi_target) b\nON b.kode_kegiatan = a.kode_kegiatan AND b.tahun = a.tahun AND a.tahun=2015 AND a.bulan = 10	\nSET a.target_fisik = b.fisik_b10, a.target_keuangan = b.keu_b10, a.target_kinerja = b.kinerja_b10;\n\nUPDATE kegiatan_realisasi a\nINNER JOIN ( SELECT * FROM kegiatan_realisasi_target) b\nON b.kode_kegiatan = a.kode_kegiatan AND b.tahun = a.tahun AND a.tahun=2015 AND a.bulan = 11	\nSET a.target_fisik = b.fisik_b11, a.target_keuangan = b.keu_b11, a.target_kinerja = b.kinerja_b11;\n\nUPDATE kegiatan_realisasi a\nINNER JOIN ( SELECT * FROM kegiatan_realisasi_target) b\nON b.kode_kegiatan = a.kode_kegiatan AND b.tahun = a.tahun AND a.tahun=2015 AND a.bulan = 12	\nSET a.target_fisik = b.fisik_b12, a.target_keuangan = b.keu_b12, a.target_kinerja = b.kinerja_b12;\n','update kegiatan realisasi tambah kolom target',NULL),
(22,'CREATE TABLE `teppa`.`menus` (\n	`menu_id` int(11)  NOT NULL AUTO_INCREMENT,\n	`menu_level` integer DEFAULT 0,\n	`menu_description` varchar(255) NOT NULL,\n	`menu_name` varchar(255) NOT NULL,\n	`iconcls` varchar(45) DEFAULT NULL,\n	`icon` varchar(255) DEFAULT NULL,\n	`active` int(11) NOT NULL DEFAULT 1,\n	PRIMARY KEY (`menu_id`)\n) ENGINE=`InnoDB` COMMENT=\'\' CHECKSUM=0 DELAY_KEY_WRITE=0;\n\ninsert into menus (menu_level, menu_description, menu_name)\nselect distinct 1, menu1, menu1 from vw_modules where menu1 <> \'\'\n\ninsert into menus (menu_level, menu_description, menu_name)\nselect distinct 2, menu2, menu2 from vw_modules where menu2 <> \'\'\n\ninsert into menus (menu_level, menu_description, menu_name)\nselect distinct 3, menu3, menu3 from vw_modules where menu3 <> \'\'\n\ninsert into menus (menu_level, menu_description, menu_name)\nselect distinct 4, menu4, menu4 from vw_modules where menu4 <> \'\'\n\ninsert into menus (menu_level, menu_description, menu_name)\nselect distinct 5, menu5, menu5 from vw_modules where menu5 <> \'\'\n','menus-teppa',NULL),
(23,'select \r\n	x.*, \r\n	(100*(x.target_keuangan/x.anggaran)) target_keuangan_prosen,\r\n	(100*(x.realisasi_keuangan/x.anggaran)) realisasi_keuangan_prosen,\r\n	((100*(x.target_keuangan/x.anggaran)) - (100*(x.realisasi_keuangan/x.anggaran))) deviasi_keuangan_prosen,\r\n	x.target_fisik target_fisik_prosen, \r\n	x.realisasi_fisik realisasi_fisik_prosen,\r\n	(x.target_fisik - x.realisasi_fisik) deviasi_fisik_prosen\r\nfrom (\r\n	select t1.tahun, t1.kode_instansi, t1.instansi, t1.kode_kegiatan, t1.kegiatan, t1.koordinator, t1.anggaran,\r\n		get_target_keuangan_keg(t1.tahun, t1.kode_kegiatan, t1.bulan) target_keuangan,\r\n		get_realisasi_keuangan_keg_yll_kode(t1.tahun, t1.bulan+1, t1.kode_kegiatan) realisasi_keuangan,\r\n		get_target_fisik_keg(t1.tahun, t1.kode_kegiatan, t1.bulan) target_fisik,\r\n		get_realisasi_fisik_keg_kode(t1.tahun, t1.bulan+1, t1.kode_kegiatan) realisasi_fisik\r\n	from kegiatan_realisasi t1\r\n	where t1.tahun=2016 and t1.bulan = 5 \r\n) x where 1=1 and ((100*(x.target_keuangan/x.anggaran)) - (100*(x.realisasi_keuangan/x.anggaran)) BETWEEN 10 and 1000)\r\nand ((x.target_fisik - x.realisasi_fisik) BETWEEN 10 and 1000)','deviasi realisasi','2016-07-21 15:13:55'),
(24,'select \r\n	x1.tahun, x1.kode_instansi, x1.instansi, count(x1.kode_kegiatan) jml_kegiatan\r\nfrom (\r\n	select \r\n		x.*, \r\n		(100*(x.target_keuangan/x.anggaran)) target_keuangan_prosen,\r\n		(100*(x.realisasi_keuangan/x.anggaran)) realisasi_keuangan_prosen,\r\n		((100*(x.target_keuangan/x.anggaran)) - (100*(x.realisasi_keuangan/x.anggaran))) deviasi_keuangan_prosen,\r\n		x.target_fisik target_fisik_prosen, \r\n		x.realisasi_fisik realisasi_fisik_prosen,\r\n		(x.target_fisik - x.realisasi_fisik) deviasi_fisik_prosen\r\n	from (\r\n		select t1.tahun, t1.kode_instansi, t1.instansi, t1.kode_kegiatan, t1.kegiatan, t1.koordinator, t1.anggaran,\r\n			get_target_keuangan_keg(t1.tahun, t1.kode_kegiatan, t1.bulan) target_keuangan,\r\n			get_realisasi_keuangan_keg_yll_kode(t1.tahun, t1.bulan+1, t1.kode_kegiatan) realisasi_keuangan,\r\n			get_target_fisik_keg(t1.tahun, t1.kode_kegiatan, t1.bulan) target_fisik,\r\n			get_realisasi_fisik_keg_kode(t1.tahun, t1.bulan+1, t1.kode_kegiatan) realisasi_fisik\r\n		from kegiatan_realisasi t1\r\n		where t1.tahun=2016 and t1.bulan = 5 \r\n	) x where 1=1 and ((100*(x.target_keuangan/x.anggaran)) - (100*(x.realisasi_keuangan/x.anggaran)) BETWEEN 10 and 1000)\r\n	and ((x.target_fisik - x.realisasi_fisik) BETWEEN 10 and 1000)\r\n) x1 \r\ngroup by x1.tahun, x1.kode_instansi, x1.instansi',NULL,'2016-07-22 03:30:38'),
(25,'select t1.tahun, t1.kode_instansi, t1.instansi, t1.kode_urusan, t1.urusan, \r\n	t1.kode_program, t1.program, t1.kode_kegiatan, t1.kegiatan,\r\n	t1.anggaran, t2.output \r\nfrom teppa.anggaran_kegiatan t1 \r\njoin (\r\n	select tahun, id_anggaran_kegiatan, group_concat(replace(indikator,\';\', \',\'), \':\', nilai SEPARATOR \'| \') as output\r\n	FROM anggaran_kegiatan_output where tahun=2016\r\n	group by tahun, id_anggaran_kegiatan ) t2\r\nOn (t2.id_anggaran_kegiatan=t1.id_anggaran_kegiatan and t2.tahun=t1.tahun)\r\nwhere t1.tahun=2016','Integrasi dengan eData untuk angagran tahun 2016','2016-08-25 05:59:13'),
(26,'select t1.kode_instansi, t1.instansi, t1.kode_urusan, t1.urusan, t1.kode_program, t1.program, \n	t1.kode_kegiatan, t1.kegiatan, t1.anggaran keuangan_target, \n	t2.realisasi_fisik_prosen, t3.rerata_realisasi_output\nfrom anggaran_kegiatan t1\nleft join (\n	select tahun, kode_kegiatan, realisasi_keuangan, sdm, realisasi_fisik_prosen \n	from kegiatan_realisasi where bulan=1\n) t2 on (t2.tahun=t1.tahun and t2.kode_kegiatan=t1.kode_kegiatan)\nleft join (\n	select tahun, kode_kegiatan, avg(100*realisasi_nilai_nominal/nilai_nominal) rerata_realisasi_output\n	from anggaran_kegiatan_output_realisasi where bulan=1\n	group by tahun, kode_kegiatan\n) t3 on (t3.tahun=t1.tahun and t3.kode_kegiatan=t1.kode_kegiatan)\nwhere t1.tahun=2016 and t1.kode_instansi=\'11\'','rekap lkpj','2016-08-31 15:12:34'),
(27,'select tx1.tahun, tx1.bulan, tx1.kode_urusan, SUBSTRING_INDEX(tx1.kode_program,\'.\',-1) kode_program_distinct, \r\n	tx1.program,	count(*) jml_kegiatan, \r\n	avg(100*tx1.keuangan_realisasi/tx1.keuangan_target) capaian_keuangan, \r\navg(tx1.capaian_output) capaian_output\r\nfrom (\r\n	select t1.tahun, t1.bulan, t1.kode_instansi, t1.instansi, t1.kode_urusan, t1.urusan, t1.kode_program, t1.program, \r\n			t1.kode_kegiatan, t1.kegiatan, t1.anggaran keuangan_target, t1.realisasi_keuangan keuangan_realisasi,\r\n	t2.capaian_output\r\n	from kegiatan_realisasi t1\r\n	JOIN (\r\n		select tahun, bulan, kode_kegiatan, avg(100*realisasi_nilai_nominal/nilai_nominal) capaian_output \r\n		from anggaran_kegiatan_output_realisasi\r\n		group by tahun, bulan, kode_kegiatan\r\n	) t2 ON (t2.tahun=t1.tahun and t2.bulan=t1.bulan and t2.kode_kegiatan=t1.kode_kegiatan)\r\n	where t1.tahun=2016 and t1.kode_urusan=\'1.07\' and t1.bulan=1\r\n	order by t1.kode_kegiatan\r\n) tx1\r\ngroup by tx1.tahun, tx1.bulan, tx1.kode_urusan, kode_program_distinct, tx1.program','rekap lpkj per urusan','2016-09-01 02:06:34'),
(28,'insert into batas_entry (jenis, tahun, bulan, tgl_batas) values \r\n(\'TEPPA\', 2017, 1, \'2017-02-08 00:00:01\'),\r\n(\'TEPPA\', 2017, 2, \'2017-03-08 00:00:01\'),\r\n(\'TEPPA\', 2017, 3, \'2017-04-08 00:00:01\'),\r\n(\'TEPPA\', 2017, 4, \'2017-05-08 00:00:01\'),\r\n(\'TEPPA\', 2017, 5, \'2017-06-08 00:00:01\'),\r\n(\'TEPPA\', 2017, 6, \'2017-07-08 00:00:01\'),\r\n(\'TEPPA\', 2017, 7, \'2017-08-08 00:00:01\'),\r\n(\'TEPPA\', 2017, 8, \'2017-09-08 00:00:01\'),\r\n(\'TEPPA\', 2017, 9, \'2017-10-08 00:00:01\'),\r\n(\'TEPPA\', 2017, 10, \'2017-11-08 00:00:01\'),\r\n(\'TEPPA\', 2017, 11, \'2017-12-08 00:00:01\'),\r\n(\'TEPPA\', 2017, 12, \'2018-01-08 00:00:01\');','insert tanggal batas entry teppa','2016-09-02 02:14:45'),
(29,'select \r\n	t1.id_kegiatan_realisasi_target, t1.id_anggaran_kegiatan, t1.id_instansi, t1.kode_instansi, t1.instansi, \r\n	t1.id_urusan, t1.kode_urusan, t1.urusan, t1.id_program, t1.kode_program, t1.program, \r\n	t1.id_kegiatan, t1.kode_kegiatan, t1.kegiatan, t1.tahun, t1.anggaran, \r\n	t1.keu_b01, \r\n	t1.keu_b01+t1.keu_b02 keu_b02, \r\n	t1.keu_b01+t1.keu_b02+t1.keu_b03 keu_b03, \r\n	t1.keu_b01+t1.keu_b02+t1.keu_b03+t1.keu_b04 keu_b04, \r\n	t1.keu_b01+t1.keu_b02+t1.keu_b03+t1.keu_b04+t1.keu_b05 keu_b05, \r\n	t1.keu_b01+t1.keu_b02+t1.keu_b03+t1.keu_b04+t1.keu_b05+t1.keu_b06 keu_b06, \r\n	t1.keu_b01+t1.keu_b02+t1.keu_b03+t1.keu_b04+t1.keu_b05+t1.keu_b06+t1.keu_b07 keu_b07, \r\n	t1.keu_b01+t1.keu_b02+t1.keu_b03+t1.keu_b04+t1.keu_b05+t1.keu_b06+t1.keu_b07+t1.keu_b08 keu_b08, \r\n	t1.keu_b01+t1.keu_b02+t1.keu_b03+t1.keu_b04+t1.keu_b05+t1.keu_b06+t1.keu_b07+t1.keu_b08+t1.keu_b09 keu_b09, \r\n	t1.keu_b01+t1.keu_b02+t1.keu_b03+t1.keu_b04+t1.keu_b05+t1.keu_b06+t1.keu_b07+t1.keu_b08+t1.keu_b09+t1.keu_b10 keu_b10, \r\n	t1.keu_b01+t1.keu_b02+t1.keu_b03+t1.keu_b04+t1.keu_b05+t1.keu_b06+t1.keu_b07+t1.keu_b08+t1.keu_b09+t1.keu_b10+t1.keu_b11 keu_b11, \r\n	t1.keu_b01+t1.keu_b02+t1.keu_b03+t1.keu_b04+t1.keu_b05+t1.keu_b06+t1.keu_b07+t1.keu_b08+t1.keu_b09+t1.keu_b10+t1.keu_b11+t1.keu_b12 keu_b12, \r\n	t1.fisik_b01, t1.fisik_b02, t1.fisik_b03, t1.fisik_b04, t1.fisik_b05, t1.fisik_b06, \r\n	t1.fisik_b07, t1.fisik_b08, t1.fisik_b09, t1.fisik_b10, t1.fisik_b11, t1.fisik_b12, \r\n	t1.kinerja_b01, t1.kinerja_b02, t1.kinerja_b03, t1.kinerja_b04, t1.kinerja_b05, t1.kinerja_b06, \r\n	t1.kinerja_b07, t1.kinerja_b08, t1.kinerja_b09, t1.kinerja_b10, t1.kinerja_b11, t1.kinerja_b12,\r\n	t2.*\r\nfrom kegiatan_realisasi_target t1 \r\nleft join (\r\n	SELECT \r\n		tahun, kode_kegiatan,\r\n		sum(if(bulan=1, realisasi_keuangan, 0)) realisasi_keuangan_b01, \r\n		sum(if(bulan=2, realisasi_keuangan, 0)) realisasi_keuangan_b02, \r\n		sum(if(bulan=3, realisasi_keuangan, 0)) realisasi_keuangan_b03, \r\n		sum(if(bulan=4, realisasi_keuangan, 0)) realisasi_keuangan_b04, \r\n		sum(if(bulan=5, realisasi_keuangan, 0)) realisasi_keuangan_b05, \r\n		sum(if(bulan=6, realisasi_keuangan, 0)) realisasi_keuangan_b06,\r\n		sum(if(bulan=7, realisasi_keuangan, 0)) realisasi_keuangan_b07,\r\n		sum(if(bulan=8, realisasi_keuangan, 0)) realisasi_keuangan_b08,\r\n		sum(if(bulan=9, realisasi_keuangan, 0)) realisasi_keuangan_b09,\r\n		sum(if(bulan=10, realisasi_keuangan, 0)) realisasi_keuangan_b10,\r\n		sum(if(bulan=11, realisasi_keuangan, 0)) realisasi_keuangan_b11,\r\n		sum(if(bulan=12, realisasi_keuangan, 0)) realisasi_keuangan_b12,\r\n		sum(if(bulan=1, realisasi_fisik_prosen, 0)) realisasi_fisik_prosen_b01, \r\n		sum(if(bulan=2, realisasi_fisik_prosen, 0)) realisasi_fisik_prosen_b02, \r\n		sum(if(bulan=3, realisasi_fisik_prosen, 0)) realisasi_fisik_prosen_b03, \r\n		sum(if(bulan=4, realisasi_fisik_prosen, 0)) realisasi_fisik_prosen_b04, \r\n		sum(if(bulan=5, realisasi_fisik_prosen, 0)) realisasi_fisik_prosen_b05, \r\n		sum(if(bulan=6, realisasi_fisik_prosen, 0)) realisasi_fisik_prosen_b06,\r\n		sum(if(bulan=7, realisasi_fisik_prosen, 0)) realisasi_fisik_prosen_b07,\r\n		sum(if(bulan=8, realisasi_fisik_prosen, 0)) realisasi_fisik_prosen_b08,\r\n		sum(if(bulan=9, realisasi_fisik_prosen, 0)) realisasi_fisik_prosen_b09,\r\n		sum(if(bulan=10, realisasi_fisik_prosen, 0)) realisasi_fisik_prosen_b10,\r\n		sum(if(bulan=11, realisasi_fisik_prosen, 0)) realisasi_fisik_prosen_b11,\r\n		sum(if(bulan=12, realisasi_fisik_prosen, 0)) realisasi_fisik_prosen_b12,\r\n		sum(if(bulan=1, is_entry_tepat_waktu_date(tahun, bulan, tgl_update), 0)) entry_tepat_waktu_b01, \r\n		sum(if(bulan=2, is_entry_tepat_waktu_date(tahun, bulan, tgl_update), 0)) entry_tepat_waktu_b02, \r\n		sum(if(bulan=3, is_entry_tepat_waktu_date(tahun, bulan, tgl_update), 0)) entry_tepat_waktu_b03, \r\n		sum(if(bulan=4, is_entry_tepat_waktu_date(tahun, bulan, tgl_update), 0)) entry_tepat_waktu_b04, \r\n		sum(if(bulan=5, is_entry_tepat_waktu_date(tahun, bulan, tgl_update), 0)) entry_tepat_waktu_b05, \r\n		sum(if(bulan=6, is_entry_tepat_waktu_date(tahun, bulan, tgl_update), 0)) entry_tepat_waktu_b06,\r\n		sum(if(bulan=7, is_entry_tepat_waktu_date(tahun, bulan, tgl_update), 0)) entry_tepat_waktu_b07, \r\n		sum(if(bulan=8, is_entry_tepat_waktu_date(tahun, bulan, tgl_update), 0)) entry_tepat_waktu_b08, \r\n		sum(if(bulan=9, is_entry_tepat_waktu_date(tahun, bulan, tgl_update), 0)) entry_tepat_waktu_b09, \r\n		sum(if(bulan=10, is_entry_tepat_waktu_date(tahun, bulan, tgl_update), 0)) entry_tepat_waktu_b10, \r\n		sum(if(bulan=11, is_entry_tepat_waktu_date(tahun, bulan, tgl_update), 0)) entry_tepat_waktu_b11, \r\n		sum(if(bulan=12, is_entry_tepat_waktu_date(tahun, bulan, tgl_update), 0)) entry_tepat_waktu_b12\r\n	FROM kegiatan_realisasi where tahun=2016\r\n	group by tahun, kode_kegiatan\r\n) t2 ON (t2.kode_kegiatan=t1.kode_kegiatan and t2.tahun=t1.tahun)\r\nwhere t1.tahun=2016\r\n\r\n','api get kegiatan lengkap','2016-09-14 06:29:11'),
(30,'delete from sirup_skpd where idkldi=\'D67\';\ndelete from sirup_skpd_penyedia  where idkldi=\'D67\';\ndelete from sirup_paket_penyedia where idkldi=\'D67\';\ndelete from sirup_paket_penyedia_string where idkldi=\'D67\';\ndelete from sirup_skpd_swakelola where idkldi=\'D67\';\ndelete from sirup_paket_swakelola where idkldi=\'D67\';\ndelete from sirup_paket_swakelola_string where idkldi=\'D67\';',NULL,'2016-10-02 15:41:47'),
(31,'SELECT t1.id_kegiatan_pengadaan, t1.id_instansi, t1.kode_kegiatan, t1.tahun, t1.bulan, \r\nt1.paket_pekerjaan, t1.id_jenis_pengadaan, t1.jenis_pengadaan, t1.id_jenis_belanja_pengadaan, \r\nt1.jenis_belanja_pengadaan, t1.volume, t1.id_metode_pengadaan, t1.metode_pengadaan, t1.anggaran, \r\nt1.rencana_awal_pengadaan, t1.rencana_selesai_pengadaan, t1.rencana_awal_pelaksanaan, \r\nt1.rencana_selesai_pelaksanaan, t1.nama_vendor, t1.nilai_kontrak, t1.nomor_kontrak, \r\nt1.tgl_kontrak, t1.waktu_pelaksanaan, t1.tgl_selesai, t1.realisasi_fisik, t1.realisasi_keu, \r\nt1.keterangan_pekerjaan, t1.keterangan_realisasi, t1.keterangan, t1.user_input, \r\nt1.tgl_input, t1.user_update, t1.tgl_update, t1.file, t1.id_pengadaan, \r\nt1.realisasi_awal_pengadaan, t1.realisasi_selesai_pengadaan, \r\nt1.realisasi_awal_pelaksanaan, t1.realisasi_selesai_pelaksanaan\r\nFROM kegiatan_pengadaan t1\r\n\r\ncreate table sirup_skpd_map as \r\nselect distinct t2.idsatker, t2.namasatker from sirup_paket_penyedia_string t2 where t2.idkldi=\'D67\'\r\n\r\nselect  t2.* from sirup_paket_penyedia_string t2 where t2.idkldi=\'D67\'\r\n\r\ninsert into kegiatan_pengadaan (id_instansi, kode_kegiatan, tahun, bulan, paket_pekerjaan, id_jenis_pengadaan, jenis_pengadaan, id_jenis_belanja_pengadaan, jenis_belanja_pengadaan, volume, id_metode_pengadaan, metode_pengadaan, anggaran, rencana_awal_pengadaan, rencana_selesai_pengadaan, rencana_awal_pelaksanaan, rencana_selesai_pelaksanaan, nama_vendor, nilai_kontrak, nomor_kontrak, tgl_kontrak, waktu_pelaksanaan, tgl_selesai, realisasi_fisik, realisasi_keu, keterangan_pekerjaan, keterangan_realisasi, keterangan, user_input, tgl_input, user_update, tgl_update, file, id_pengadaan, realisasi_awal_pengadaan, realisasi_selesai_pengadaan, realisasi_awal_pelaksanaan, realisasi_selesai_pelaksanaan) \r\nselect  \r\n	(select id_instansi from sirup_skpd_map where idsatker=t2.idsatker) id_instansi,\r\n	t2.kode_rekening kode_kegiatan, 2016 tahun, 1 bulan, \r\n	t2.namapaket paket_pekerjaan, \r\n	(select id_jenis_pengadaan from reff_jenis_pengadaan where jenis_pengadaan=t2.jenis_pengadaan) id_jenis_pengadaan, \r\n	t2.jenis_pengadaan jenis_pengadaan, \r\n	(select id_jenis_belanja_pengadaan from reff_jenis_belanja_pengadaan where jenis_belanja_pengadaan=t2.jenis_belanja)  id_jenis_belanja_pengadaan, \r\n	t2.jenis_belanja jenis_belanja_pengadaan, t2.volume volume, \r\n	(select id_metode_pengadaan from reff_metode_pengadaan where metode_pengadaan=t2.metode_pemilihan) id_metode_pengadaan, \r\n	t2.metode_pemilihan metode_pengadaan, t2.pagu anggaran, \r\n	str_to_date(t2.tgl_awal_pengadaan, \'%d-%m-%Y\') rencana_awal_pengadaan, str_to_date(t2.tgl_akhir_pengadaan, \'%d-%m-%Y\') rencana_selesai_pengadaan, \r\n	str_to_date(t2.tgl_awal_pekerjaan, \'%d-%m-%Y\') rencana_awal_pelaksanaan, \r\n	str_to_date(t2.tgl_akhir_pekerjaan, \'%d-%m-%Y\') rencana_selesai_pelaksanaan, \r\n	\'\' nama_vendor, null nilai_kontrak, \'\' nomor_kontrak, \r\n	null tgl_kontrak, null waktu_pelaksanaan, null tgl_selesai, null realisasi_fisik, null realisasi_keu, \r\n	t2.keterangan keterangan_pekerjaan, null keterangan_realisasi, concat_ws(\'|\', t2.kegiatan, t2.idpaket, t2.idsatker) keterangan, \'exp-sys\' user_input, \r\n	NOW() tgl_input, \'exp-sys\' user_update, now() tgl_update, \'\' file, null id_pengadaan, \r\n	null realisasi_awal_pengadaan, null realisasi_selesai_pengadaan, \r\n	null realisasi_awal_pelaksanaan, null realisasi_selesai_pelaksanaan\r\nfrom sirup_paket_penyedia_string t2 where t2.idkldi=\'D67\'\r\n\r\nupdate sirup_skpd_map set tahun=2016',NULL,'2016-10-05 06:40:00'),
(32,'-- REKAP SIRUP --\nselect t1.tahun,  t1.bulan, t1.jumlah_paket penyedia_jumlah_paket, t1.total_pagu penyedia_total_pagu,\n	t2.jumlah_paket swakelola_jumlah_paket, t2.total_pagu swakelola_total_pagu\nfrom (\n	select \'Paket Penyedia\' Jenis, tahun, bulan, count(*) jumlah_paket, sum(anggaran) total_pagu \n	from kegiatan_pengadaan where tahun=2016 and bulan=1\n) t1\njoin (\n	select \'Paket Swakelola\' Jenis, tahun, bulan, count(*) jumlah_paket, sum(anggaran) total_pagu \n	from kegiatan_swakelola where tahun=2016 and bulan=1\n) t2 on (t2.tahun=t1.tahun and t2.bulan=t1.bulan)\n\nselect t1.tahun, t1.kode_instansi, t1.instansi, \n	t2.jumlah_paket penyedia_jumlah_paket, t2.total_pagu penyedia_total_pagu,\n	t3.jumlah_paket penyedia_jumlah_paket, t3.total_pagu penyedia_total_pagu\nfrom reff_instansi t1\nleft join (\n	select \'Paket Penyedia\' Jenis, tahun, id_instansi, count(*) jumlah_paket, sum(anggaran) total_pagu \n	from kegiatan_pengadaan where tahun=2016 and bulan=1\n	group by id_instansi\n) t2 ON (t2.tahun=t1.tahun and t2.id_instansi=t1.id_instansi)\nleft join (\n	select \'Paket Swakelola\' Jenis, tahun, id_instansi, count(*) jumlah_paket, sum(anggaran) total_pagu \n	from kegiatan_swakelola where tahun=2016 and bulan=1\n	group by id_instansi \n) t3 ON (t3.tahun=t1.tahun and t3.id_instansi=t1.id_instansi)\nwhere t1.tahun=2016\n\n-- REKAP PER JENIS PENGADAAN --\nselect \'Paket Penyedia\' Jenis, tahun, bulan,\n	sum(if(id_jenis_pengadaan=1, 1,0)) jumlah_paket_1, \n	sum(if(id_jenis_pengadaan=1, anggaran,0)) total_pagu_1, \n	sum(if(id_jenis_pengadaan=2, 1,0)) jumlah_paket_2, \n	sum(if(id_jenis_pengadaan=2, anggaran,0)) total_pagu_2,		\n	sum(if(id_jenis_pengadaan=3, 1,0)) jumlah_paket_3, \n	sum(if(id_jenis_pengadaan=3, anggaran,0)) total_pagu_3,\n	sum(if(id_jenis_pengadaan=4, 1,0)) jumlah_paket_4, \n	sum(if(id_jenis_pengadaan=4, anggaran,0)) total_pagu_4\nfrom kegiatan_pengadaan where tahun=2016 and bulan=1\n\nselect t1.tahun, t1.kode_instansi, t1.instansi, \n	t2.jumlah_paket_1, t2.jumlah_paket_2, t2.jumlah_paket_3, t2.jumlah_paket_4,\n	t2.total_pagu_1, t2.total_pagu_2, t2.total_pagu_3, t2.total_pagu_4 \nfrom reff_instansi t1\nleft join (\n	select \'Paket Penyedia\' Jenis, tahun, id_instansi, \n		sum(if(id_jenis_pengadaan=1, 1,0)) jumlah_paket_1, \n		sum(if(id_jenis_pengadaan=1, anggaran,0)) total_pagu_1, \n		sum(if(id_jenis_pengadaan=2, 1,0)) jumlah_paket_2, \n		sum(if(id_jenis_pengadaan=2, anggaran,0)) total_pagu_2,		\n		sum(if(id_jenis_pengadaan=3, 1,0)) jumlah_paket_3, \n		sum(if(id_jenis_pengadaan=3, anggaran,0)) total_pagu_3,\n		sum(if(id_jenis_pengadaan=4, 1,0)) jumlah_paket_4, \n		sum(if(id_jenis_pengadaan=4, anggaran,0)) total_pagu_4\n	from kegiatan_pengadaan where tahun=2016 and bulan=1\n	group by id_instansi\n) t2 ON (t2.tahun=t1.tahun and t2.id_instansi=t1.id_instansi)\nwhere t1.tahun=2016\n\n-- REKAP PER JENIS BELANJA PENGADAAN --\nselect \'Paket Penyedia\' Jenis, tahun, bulan,\n	sum(if(id_jenis_belanja_pengadaan=1, 1,0)) jumlah_paket_1, \n	sum(if(id_jenis_pengadaan=1, anggaran,0)) total_pagu_1, \n	sum(if(id_jenis_pengadaan=2, 1,0)) jumlah_paket_2, \n	sum(if(id_jenis_pengadaan=2, anggaran,0)) total_pagu_2,		\n	sum(if(id_jenis_pengadaan=3, 1,0)) jumlah_paket_3, \n	sum(if(id_jenis_pengadaan=3, anggaran,0)) total_pagu_3,\n	sum(if(id_jenis_pengadaan=4, 1,0)) jumlah_paket_4, \n	sum(if(id_jenis_pengadaan=4, anggaran,0)) total_pagu_4,\n	sum(if(id_jenis_pengadaan=5, 1,0)) jumlah_paket_5, \n	sum(if(id_jenis_pengadaan=5, anggaran,0)) total_pagu_5\nfrom kegiatan_pengadaan where tahun=2016 and bulan=1\n\nselect t1.tahun, t1.kode_instansi, t1.instansi, \n	t2.jumlah_paket_1, t2.jumlah_paket_2, t2.jumlah_paket_3,  t2.jumlah_paket_4,  t2.jumlah_paket_5, \n	t2.total_pagu_1, t2.total_pagu_2, t2.total_pagu_3, t2.total_pagu_4, t2.total_pagu_5   \nfrom reff_instansi t1\nleft join (\n	select \'Paket Penyedia\' Jenis, tahun, id_instansi, \n		sum(if(id_jenis_pengadaan=1, 1,0)) jumlah_paket_1, \n		sum(if(id_jenis_pengadaan=1, anggaran,0)) total_pagu_1, \n		sum(if(id_jenis_pengadaan=2, 1,0)) jumlah_paket_2, \n		sum(if(id_jenis_pengadaan=2, anggaran,0)) total_pagu_2,		\n		sum(if(id_jenis_pengadaan=3, 1,0)) jumlah_paket_3, \n		sum(if(id_jenis_pengadaan=3, anggaran,0)) total_pagu_3,	\n		sum(if(id_jenis_pengadaan=4, 1,0)) jumlah_paket_4, \n		sum(if(id_jenis_pengadaan=4, anggaran,0)) total_pagu_4,	\n		sum(if(id_jenis_pengadaan=5, 1,0)) jumlah_paket_5, \n		sum(if(id_jenis_pengadaan=5, anggaran,0)) total_pagu_5\n	from kegiatan_pengadaan where tahun=2016 and bulan=1\n	group by id_instansi\n) t2 ON (t2.tahun=t1.tahun and t2.id_instansi=t1.id_instansi)\nwhere t1.tahun=2016\n\n',NULL,'2016-10-08 01:30:56'),
(33,'INSERT INTO `modules` (`module_id`, `module`, `name`, `description`, `menu`, `iconcls`, `icon`, `active`, `onmenu`, `onview`) \nVALUES (\'dashboard-rup\', \'DashboardRUP\', \'Dashboard RUP\', \'Dashboard Rencana Uum Pengadaan Kabupaten\', \'013;Raport SKPD/\', \'icon-module\', \'icon.png\', 0, 0, \'tabpanel\'); \n\nINSERT INTO `actions` (`module_id`, `action_id`, `option`, `action`, `description`, `log`) VALUES \n ( \'dashboard-rup\',\'dashboard_view\',\'dashboard\',\'view\',\'Lihat dashboard RUP Kabupaten\',0 );\n',NULL,'2016-10-08 05:13:04'),
(34,'INSERT INTO `sismon2`.`modules` (`module_id`, `module`, `name`, `description`, `menu`, `iconcls`, `icon`, `active`, `onmenu`, `onview`) VALUES (\'dashboard-rup-detail-skpd\', \'DashboardRUPDetailSKPD\', \'Dashboard RUP Detail SKPD\', \'Dashboard RUP Detail SKPD\', \'013;Raport SKPD/\', \'icon-module\', \'icon.png\', \'1\', \'0\', \'window\');\r\n\r\nINSERT INTO `sismon2`.`actions` (`module_id`, `action_id`, `option`, `action`, `description`, `log`) VALUES (\'dashboard-rup-detail-skpd\', \'skpd_list\', \'skpd\', \'list\', \'Lihat daftar detail pada SKPD\', \'1\');\r\n\r\n',NULL,'2016-10-10 00:32:12'),
(35,'select * from format_datagender where  grup_format=\'format-1\'\n\ninsert into data_pilah (judul_data_pilah, aktif) \nselect title, 1 from format_datagender where  grup_format=\'format-1\'\n\nupdate data_pilah set kode_data_pilah= lpad(id_data_pilah, 2, \'0\')\n\ninsert into data_pilah_baris (kode_data_pilah, no_urut, kode_baris, nama_baris, aktif)\nvalues(\'16\',01, \'16.01\', \'Gamping\',1),\n(\'16\',02, \'16.02\', \'Godean\',1),\n(\'16\',03, \'16.03\', \'Moyudan\',1),\n(\'16\',04, \'16.04\', \'Minggir\',1),\n(\'16\',05, \'16.05\', \'Seyegan\',1),\n(\'16\',06, \'16.06\', \'Mlati\',1),\n(\'16\',07, \'16.07\', \'Depok\',1),\n(\'16\',08, \'16.08\', \'Berbah\',1),\n(\'16\',09, \'16.09\', \'Prambanan\',1),\n(\'16\',10, \'16.10\', \'Kalasan\',1),\n(\'16\',11, \'16.11\', \'Ngemplak\',1),\n(\'16\',12, \'16.12\', \'Ngaglik\',1),\n(\'16\',13, \'16.13\', \'Sleman\',1),\n(\'16\',14, \'16.14\', \'Tempel\',1),\n(\'16\',15, \'16.15\', \'Turi\',1),\n(\'16\',16, \'16.16\', \'Pakem\',1),\n(\'16\',17, \'16.17\', \'Cangkringan\',1)\n\n\ninsert into data_pilah_cell(tahun, kode_data_pilah, kode_kolom, kode_baris, val)\nvalues(2016, \'16\', \'16.04\', \'16.01\', 789)\n\nselect tc.kode_data_pilah, tc.tahun, tb.no_urut, tb.kode_baris, tb.nama_baris, tk.kode_kolom, tk.header_kolom, tk.nama_kolom, tc.val \nfrom data_pilah_cell tc\nleft join data_pilah_baris tb on (tb.kode_data_pilah=tc.kode_data_pilah and tb.kode_baris=tc.kode_baris)\nleft join data_pilah_kolom tk on (tk.kode_data_pilah=tc.kode_data_pilah and tk.kode_kolom=tc.kode_kolom)\nwhere tc.tahun=2016 and tc.kode_data_pilah=\'16\'\norder by tc.tahun, tb.kode_baris, tk.kode_kolom\n','data pilah','2018-10-02 08:31:55'),
(36,'select * from data_pilah where upper(judul_data_pilah) like \'%FORUM KOMUNIKASI%\'\n\nset @kode = \'17\';\ninsert into data_pilah_kolom (kode_data_pilah, header_kolom, kode_kolom, nama_kolom, tipe_kolom, aktif)\nvalues\n(@kode, null, concat(@kode,\'.01\'),\'Forum Komunikasi Keluarga ABK (Anak dengan Kecacatan\',0,1),\n(@kode, null, concat(@kode,\'.02\'),\'YPAC\',0,1),\n(@kode, null, concat(@kode,\'.03\'),\'Aliansi RBM\',0,1),\n(@kode, null, concat(@kode,\'.04\'),\'Jumlah\',0,1)\n\nselect * from data_pilah where upper(judul_data_pilah) like \'%ANGKA PARTISIPASI KASAR%\'\nset @kode = \'18\';\ninsert into data_pilah_kolom (kode_data_pilah, header_kolom, kode_kolom, nama_kolom, tipe_kolom, aktif)\nvalues\n(@kode, \'SD\', concat(@kode,\'.01\'),\'L\',0,1),\n(@kode, \'SD\', concat(@kode,\'.02\'),\'P\',0,1),\n(@kode, \'SD\', concat(@kode,\'.03\'),\'L+P\',0,1),\n(@kode, \'SLTP\', concat(@kode,\'.04\'),\'L\',0,1),\n(@kode, \'SLTP\', concat(@kode,\'.05\'),\'P\',0,1),\n(@kode, \'SLTP\', concat(@kode,\'.06\'),\'L+P\',0,1);\n\nselect * from data_pilah where upper(judul_data_pilah) like \'%ANGKA PARTISIPASI SEKOLAH%\'\nset @kode = \'19\';\ninsert into data_pilah_kolom (kode_data_pilah, header_kolom, kode_kolom, nama_kolom, tipe_kolom, aktif)\nvalues\n(@kode, \'7-12\', concat(@kode,\'.01\'),\'L\',0,1),\n(@kode, \'7-12\', concat(@kode,\'.02\'),\'P\',0,1),\n(@kode, \'7-12\', concat(@kode,\'.03\'),\'L+P\',0,1),\n(@kode, \'13-15\', concat(@kode,\'.04\'),\'L\',0,1),\n(@kode, \'13-15\', concat(@kode,\'.05\'),\'P\',0,1),\n(@kode, \'13-15\', concat(@kode,\'.06\'),\'L+P\',0,1);\n\nselect * from data_pilah where upper(judul_data_pilah) like \'%ANGKA PARTISIPASI MURNI%\'\nset @kode = \'20\';\ninsert into data_pilah_kolom (kode_data_pilah, header_kolom, kode_kolom, nama_kolom, tipe_kolom, aktif)\nvalues\n(@kode, \'SD\', concat(@kode,\'.01\'),\'L\',0,1),\n(@kode, \'SD\', concat(@kode,\'.02\'),\'P\',0,1),\n(@kode, \'SD\', concat(@kode,\'.03\'),\'L+P\',0,1),\n(@kode, \'SLTP\', concat(@kode,\