('01','02','01','1.1','Angka sengketa pengusaha-pekerja per tahun','{\"type\": \"Equation\", \"value\": null, \"operands\": {\"topLevelContainer\": [{\"type\": \"StackedFraction\", \"value\": null, \"operands\": {\"numerator\": [{\"type\": \"Symbol\", \"value\": \"a\", \"operands\": null}, {\"type\": \"Symbol\", \"value\": \"x\", \"operands\": null}, {\"type\": \"Symbol\", \"value\": \"b\", \"operands\": null}], \"denominator\": [{\"type\": \"Symbol\", \"value\": \"1\", \"operands\": null}, {\"type\": \"Symbol\", \"value\": \"0\", \"operands\": null}, {\"type\": \"Symbol\", \"value\": \"0\", \"operands\": null}, {\"type\": \"Symbol\", \"value\": \"0\", \"operands\": null}]}}, {\"type\": \"Symbol\", \"value\": \"x\", \"operands\": null}, {\"type\": \"Symbol\", \"value\": \"9\", \"operands\": null}, {\"type\": \"Symbol\", \"value\": \"0\", \"operands\": null}, {\"type\": \"Symbol\", \"value\": \"0\", \"operands\": null}, {\"type\": \"Symbol\", \"value\": \"0\", \"operands\": null}]}}','((axb)/(1000))x9000','select ((((select b.data from ref_sumberdata a \n                       inner join data_per_tahun b on a.id_sumberdata = b.id_sumber_data\n                       WHERE a.kode_sumberdata=\'00001\' and b.tahun=paramtahun and b.bulan=parambulan)*(select b.data from ref_sumberdata a \n                       inner join data_per_tahun b on a.id_sumberdata = b.id_sumber_data\n                       WHERE a.kode_sumberdata=\'00003\' and b.tahun=paramtahun and b.bulan=parambulan))/(1000))*9000)','data:image/png;base64,'),
('01','02','01','1.2','Besaran kasus yang diselesaikan dengan perjanjian bersama (PB)','{\"type\": \"Equation\", \"value\": null, \"operands\": {\"topLevelContainer\": [{\"type\": \"StackedFraction\", \"value\": null, \"operands\": {\"numerator\": [{\"type\": \"Symbol\", \"value\": \"a\", \"operands\": null}], \"denominator\": [{\"type\": \"Symbol\", \"value\": \"b\", \"operands\": null}]}}, {\"type\": \"Symbol\", \"value\": \"X\", \"operands\": null}, {\"type\": \"Symbol\", \"value\": \"8\", \"operands\": null}, {\"type\": \"Symbol\", \"value\": \"0\", \"operands\": null}, {\"type\": \"Symbol\", \"value\": \"9\", \"operands\": null}]}}','((a)/(b))X809','select ((((select b.data from ref_sumberdata a \n                       inner join data_per_tahun b on a.id_sumberdata = b.id_sumber_data\n                       WHERE a.kode_sumberdata=\'00001\' and b.tahun=paramtahun))/((select b.data from ref_sumberdata a \n                       inner join data_per_tahun b on a.id_sumberdata = b.id_sumber_data\n                       WHERE a.kode_sumberdata=\'00003\' and b.tahun=paramtahun)))*809)','data:image/png;base64,'),
